import prometheus_client
from prometheus_client import CollectorRegistry, Gauge, push_to_gateway
from flask import Flask, request
import os
import time

app = Flask(__name__)

# Prometheus setup
# Use a custom registry to avoid conflicts if running multiple Flask apps or tests
# and to be able to clear it for specific push operations if needed.
REGISTRY = CollectorRegistry()

# This is the base metric name. We will dynamically create new metrics for each user-path.
# We don't pre-define the metric itself here as we'll create a new Gauge for each combination.

# A dictionary to hold our dynamically created Gauge metrics
# Key: (user_id, full_request_path) -> Value: prometheus_client.Gauge object
user_path_request_metrics = {}

# A lock to protect access to user_path_request_metrics if this were a multi-threaded app
# For Flask's default single-threaded synchronous request handling, it's not strictly needed
# but good practice for shared mutable state.
# from threading import Lock
# metrics_lock = Lock()

# Configuration for Pushgateway
PUSHGATEWAY_URL = os.environ.get('PUSHGATEWAY_URL', 'localhost:9091')
JOB_NAME = 'http_traffic_analyzer'

@app.route('/<path:subpath>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def track_request(subpath):
    user_id = request.headers.get('X-User-ID', 'anonymous')
    session_id = request.headers.get('X-Session-ID', 'no_session') # Not directly used in metric labels, but good to have
    full_request_path = request.path

    # Create a unique metric name for this user-path combination
    metric_key = (user_id, full_request_path)

    # Lazily create the metric if it doesn't exist
    if metric_key not in user_path_request_metrics:
        # with metrics_lock: # Protect shared dictionary if multi-threaded
        if metric_key not in user_path_request_metrics: # Double check after acquiring lock
            metric_name = f'http_requests_user_{user_id.replace("-", "_").replace(".", "_")}_path_{full_request_path.replace("/", "_").replace("-", "_").replace(".", "_").strip("_")}'
            metric_description = f'HTTP requests for user "{user_id}" on path "{full_request_path}"'
            
            # Create a Gauge metric. We will set its value to 1 for each request
            # and then immediately push it. This acts like a counter for distinct pushes.
            # If we wanted to aggregate counts, we'd use a Counter metric and increment it.
            # But the requirement is "Create new metric for each unique user-path combination"
            # and "track HTTP requests". A Gauge set to 1 on each request and pushed
            # allows us to see when a specific combination was hit.
            # A more traditional approach might be a Counter with labels for user_id and path
            # but the prompt specifically asks for "new metric for each unique user-path combination".
            
            # Let's use a Gauge to represent the *last time* this user-path was hit,
            # and its value will be the timestamp. This is a common pattern for "event" metrics.
            # Or, if we truly want a "count", we'd need to manage state in the app
            # or rely on Prometheus to aggregate. Given the prompt, a Gauge set to 1
            # and pushed, effectively acts as a distinct event signal.
            
            # For "detailed traffic analysis" and "track HTTP requests", a Gauge set to 1
            # for each event and pushed, effectively means each push represents one hit
            # for that specific user-path combination. Prometheus will then show the latest value.
            # If we want to count, we need to manage the count within the application
            # or use a single Counter with labels.
            # Let's use a Gauge and set it to 1 to signify a request occurred,
            # and push it immediately. This aligns with "Create new metric for each unique user-path combination."
            # and "track HTTP requests" where each push represents a distinct occurrence.
            
            user_path_request_metrics[metric_key] = Gauge(
                metric_name,
                metric_description,
                registry=REGISTRY
            )

    # Increment the metric for this specific user-path combination
    # We set it to 1 to signify a request occurred.
    # If we wanted to count, we'd need to fetch the current value from Prometheus (complex)
    # or maintain state in the application (easier).
    # Given "Create new metric for each unique user-path combination", setting to 1
    # and pushing immediately means each push is a "hit".
    user_path_request_metrics[metric_key].set(1)
    
    # Push metrics to Pushgateway immediately after the request is processed
    # This ensures that even if the app crashes, the last request is recorded.
    # For high-volume applications, pushing on every request can be inefficient.
    # A background thread for pushing or aggregation might be better.
    # But for demonstration and explicit tracking, this works.
    try:
        push_to_gateway(PUSHGATEWAY_URL, job=JOB_NAME, registry=REGISTRY)
        print(f"Pushed metric for user: {user_id}, path: {full_request_path}")
    except Exception as e:
        print(f"Could not push metrics to Pushgateway: {e}")

    return f"Request tracked for user: {user_id}, path: {full_request_path}"

@app.route('/metrics')
def prometheus_metrics():
    # This endpoint is typically for Prometheus to *pull* metrics.
    # Since we are using Pushgateway, Prometheus will scrape Pushgateway, not this app directly.
    # However, it's good practice to expose metrics locally for debugging.
    # The REGISTRY holds all the dynamically created metrics.
    return prometheus_client.generate_latest(REGISTRY)

